mapper.select:
/* SQL ID : list 설 명 : 사용자 정보 변경 로그 목록 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY A.FRST_INQ_DTTM ASC) as lineNo
, A.FRST_INQ_DTTM as regDttm , A.USER_ID as userId , A.CHG_GBNCD as userInfoChgDivCd , A.CHGBFR_CTS as userInfoCts , A.CHGAFT_CTS as chgTarget , A.CNTN_IP as connIp , A.RGTR_ID as rgtrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID) AS regNm FROM TB_LMS_USER_INFO_CHG_HSTRY AS A WHERE A.USER_ID = #{userId}
ORDER BY A.FRST_INQ_DTTM DESC

/* SQL ID : select 설 명 : 사용자 정보 변경 로그 조회 */
SELECT A.FRST_INQ_DTTM as regDttm , A.USER_ID as userId , A.CHG_GBNCD as userInfoChgDivCd , A.CHGBFR_CTS as userInfoCts , A.CHGAFT_CTS as chgTarget , A.CNTN_IP as connIp , A.RGTR_ID as rgtrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID) AS regNm FROM TB_LMS_USER_INFO_CHG_HSTRY AS A WHERE A.USER_ID = #{userId}
AND A.FRST_INQ_DTTM = #{regDttm}

mapper.insert:
	/*
		 SQL ID : insert
		 설  명 : 사용자 정보 변경 로그 등록
 	*/
	INSERT INTO TB_LMS_USER_INFO_CHG_HSTRY (
	       FRST_INQ_DTTM
	     , USER_ID
	     , CHG_GBNCD
	     , CHGBFR_CTS
	     , CHGAFT_CTS
	     , CNTN_IP
	     , RGTR_ID
	) VALUES (
	       FN_DTTM()
	     , #{userId}
	     , #{userInfoChgDivCd}
	     , #{userInfoCts}
	     , #{chgTarget}
	     , #{connIp}
	     , #{rgtrId}
	)
